def verify_token(token: str, expected_token_type: str = "access") -> dict:
    """
    Verify and decode a JWT token with strict validation.

    Args:
        token: The JWT string to verify.
        expected_token_type: Either 'access' or 'refresh'.

    Returns:
        The decoded payload dictionary.

    Raises:
        jwt.ExpiredSignatureError: If the token has expired.
        jwt.InvalidTokenError: If the token is invalid for any reason.
        ValueError: If the token type doesn't match expectations.
    """
